import { DynamoDBClient, UpdateItemCommand, GetItemCommand } from '@aws-sdk/client-dynamodb';
import { BedrockRuntimeClient, InvokeModelCommand } from '@aws-sdk/client-bedrock-runtime';

interface CircuitState {
  failures: number;
  lastFailure: number;
  state: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
}

const FAILURE_THRESHOLD = 5;
const RECOVERY_TIMEOUT_MS = 60000; // 1 minute

async function invokeWithCircuitBreaker(
  modelId: string,
  body: string
): Promise<string> {
  const ddb = new DynamoDBClient({});
  const bedrock = new BedrockRuntimeClient({});

  // Check circuit state
  const state = await getCircuitState(ddb, modelId);

  if (state.state === 'OPEN') {
    // Check if recovery timeout has passed
    if (Date.now() - state.lastFailure > RECOVERY_TIMEOUT_MS) {
      await setCircuitState(ddb, modelId, 'HALF_OPEN');
    } else {
      throw new Error('Circuit OPEN: Service unavailable');
    }
  }

  try {
    const response = await bedrock.send(new InvokeModelCommand({
      modelId,
      body: body,
      contentType: 'application/json',
      accept: 'application/json'
    }));

    // Success - reset circuit
    if (state.state === 'HALF_OPEN' || state.failures > 0) {
      await resetCircuit(ddb, modelId);
    }

    return new TextDecoder().decode(response.body);

  } catch (error) {
    await recordFailure(ddb, modelId, state);
    throw error;
  }
}

async function recordFailure(
  ddb: DynamoDBClient,
  modelId: string,
  currentState: CircuitState
): Promise<void> {
  const newFailures = currentState.failures + 1;
  const newState = newFailures >= FAILURE_THRESHOLD ? 'OPEN' : currentState.state;

  await ddb.send(new UpdateItemCommand({
    TableName: 'CircuitBreaker',
    Key: { pk: { S: `MODEL#${modelId}` } },
    UpdateExpression: 'SET failures = :f, lastFailure = :t, circuitState = :s',
    ExpressionAttributeValues: {
      ':f': { N: String(newFailures) },
      ':t': { N: String(Date.now()) },
      ':s': { S: newState }
    }
  }));
}

async function invokeWithRetry<T>(
  operation: () => Promise<T>,
  maxRetries: number = 3,
  baseDelayMs: number = 1000
): Promise<T> {
  let lastError: Error;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await operation();
    } catch (error) {
      lastError = error as Error;

      // Don't retry non-retryable errors
      if (!isRetryable(error)) {
        throw error;
      }

      if (attempt < maxRetries) {
        // Full jitter: random delay between 0 and exponential backoff
        const exponentialDelay = baseDelayMs * Math.pow(2, attempt);
        const jitteredDelay = Math.random() * exponentialDelay;

        console.log(`Attempt ${attempt + 1} failed, retrying in ${jitteredDelay}ms`);
        await sleep(jitteredDelay);
      }
    }
  }

  throw lastError!;
}

function isRetryable(error: unknown): boolean {
  if (error instanceof Error) {
    // Bedrock rate limiting
    if (error.name === 'ThrottlingException') return true;
    // Service unavailable
    if (error.name === 'ServiceUnavailableException') return true;
    // Model overloaded
    if (error.name === 'ModelNotReadyException') return true;
    // Timeout
    if (error.name === 'TimeoutError') return true;
  }
  return false;
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

interface ModelConfig {
  modelId: string;
  region?: string;
  timeout: number;
  maxTokens: number;
}

const FALLBACK_CHAIN: ModelConfig[] = [
  { modelId: 'anthropic.claude-3-sonnet-20240229-v1:0', timeout: 30000, maxTokens: 4096 },
  { modelId: 'anthropic.claude-3-haiku-20240307-v1:0', timeout: 15000, maxTokens: 4096 },
  { modelId: 'amazon.titan-text-express-v1', timeout: 15000, maxTokens: 4096 }
];

async function invokeWithFallback(
  prompt: string,
  systemPrompt?: string
): Promise<{ response: string; modelUsed: string }> {
  const errors: Error[] = [];

  for (const config of FALLBACK_CHAIN) {
    try {
      const response = await invokeModel(prompt, systemPrompt, config);

      // Log which model was used (important for cost tracking)
      console.log(`Request served by: ${config.modelId}`);

      return {
        response,
        modelUsed: config.modelId
      };
    } catch (error) {
      console.error(`${config.modelId} failed:`, error);
      errors.push(error as Error);
      // Continue to next model in chain
    }
  }

  // All models failed
  throw new AggregateError(
    errors,
    'All models in fallback chain failed'
  );
}

import { Client } from '@opensearch-project/opensearch';
import { BedrockRuntimeClient, InvokeModelCommand } from '@aws-sdk/client-bedrock-runtime';

const SIMILARITY_THRESHOLD = 0.92; // Tune based on your use case
const CACHE_TTL_SECONDS = 3600; // 1 hour

interface CacheEntry {
  prompt: string;
  response: string;
  embedding: number[];
  timestamp: number;
  modelId: string;
}

async function invokeWithSemanticCache(
  prompt: string,
  modelId: string
): Promise<{ response: string; cached: boolean }> {
  const bedrock = new BedrockRuntimeClient({});
  const opensearch = new Client({ node: process.env.OPENSEARCH_ENDPOINT });

  // Generate embedding for the prompt
  const promptEmbedding = await generateEmbedding(prompt);

  // Search for similar cached prompts
  const searchResult = await opensearch.search({
    index: 'semantic-cache',
    body: {
      query: {
        script_score: {
          query: {
            bool: {
              must: [
                { term: { modelId } },
                { range: { timestamp: { gte: Date.now() - CACHE_TTL_SECONDS * 1000 } } }
              ]
            }
          },
          script: {
            source: "cosineSimilarity(params.query_vector, 'embedding') + 1.0",
            params: { query_vector: promptEmbedding }
          }
        }
      },
      size: 1
    }
  });

  const hits = searchResult.body.hits.hits;
  if (hits.length > 0 && hits[0]._score - 1.0 >= SIMILARITY_THRESHOLD) {
    // Cache hit!
    console.log(`Semantic cache hit (similarity: ${hits[0]._score - 1.0})`);
    return { response: hits[0]._source.response, cached: true };
  }

  // Cache miss - invoke model
  const response = await invokeModel(prompt, modelId);

  // Cache the result
  await opensearch.index({
    index: 'semantic-cache',
    body: {
      prompt,
      response,
      embedding: promptEmbedding,
      timestamp: Date.now(),
      modelId
    }
  });

  return { response, cached: false };
}

async function generateEmbedding(text: string): Promise<number[]> {
  const bedrock = new BedrockRuntimeClient({});

  const response = await bedrock.send(new InvokeModelCommand({
    modelId: 'amazon.titan-embed-text-v2:0',
    body: JSON.stringify({ inputText: text }),
    contentType: 'application/json'
  }));

  const result = JSON.parse(new TextDecoder().decode(response.body));
  return result.embedding;
}

// Simple token estimator (actual tokenization varies by model)
function estimateTokens(text: string): number {
  // Rough heuristic: ~4 characters per token for English
  // Use tiktoken or model-specific tokenizer for accuracy
  return Math.ceil(text.length / 4);
}

interface TokenBudget {
  maxInputTokens: number;
  maxOutputTokens: number;
  reservedTokens: number; // For system prompts, formatting
}

function enforceTokenBudget(
  userPrompt: string,
  systemPrompt: string,
  context: string,
  budget: TokenBudget
): { prompt: string; context: string; outputTokens: number } {
  const systemTokens = estimateTokens(systemPrompt);
  const userTokens = estimateTokens(userPrompt);
  const reservedTokens = budget.reservedTokens;

  // Calculate available tokens for context
  const availableForContext = budget.maxInputTokens 
    - systemTokens 
    - userTokens 
    - reservedTokens;

  if (availableForContext < 0) {
    throw new Error('Prompt exceeds token budget even without context');
  }

  // Truncate context if needed
  let truncatedContext = context;
  let contextTokens = estimateTokens(context);

  if (contextTokens > availableForContext) {
    // Smart truncation: prefer recent/relevant content
    truncatedContext = truncateToTokens(context, availableForContext);
    console.warn(`Context truncated from ${contextTokens} to ${availableForContext} tokens`);
  }

  // Calculate safe output token limit
  const totalInputTokens = systemTokens + userTokens + estimateTokens(truncatedContext);
  const safeOutputTokens = Math.min(
    budget.maxOutputTokens,
    budget.maxInputTokens - totalInputTokens // Some models share input/output limit
  );

  return {
    prompt: userPrompt,
    context: truncatedContext,
    outputTokens: safeOutputTokens
  };
}

function truncateToTokens(text: string, maxTokens: number): string {
  const estimated = estimateTokens(text);
  if (estimated <= maxTokens) return text;

  // Truncate from the middle to preserve start and end
  const ratio = maxTokens / estimated;
  const targetLength = Math.floor(text.length * ratio);
  const halfLength = Math.floor(targetLength / 2);

  return text.slice(0, halfLength) + '\n[...truncated...]\n' + text.slice(-halfLength);
}

interface UserQuota {
  dailyTokenLimit: number;
  monthlyTokenLimit: number;
}

const DEFAULT_QUOTAS: Record<string, UserQuota> = {
  free: { dailyTokenLimit: 10000, monthlyTokenLimit: 100000 },
  pro: { dailyTokenLimit: 100000, monthlyTokenLimit: 1000000 },
  enterprise: { dailyTokenLimit: 1000000, monthlyTokenLimit: 10000000 }
};

async function checkAndConsumeQuota(
  userId: string,
  tier: string,
  tokensToConsume: number
): Promise<{ allowed: boolean; remaining: number }> {
  const ddb = new DynamoDBClient({});
  const quota = DEFAULT_QUOTAS[tier] || DEFAULT_QUOTAS.free;

  const today = new Date().toISOString().split('T')[0];
  const month = today.slice(0, 7);

  try {
    // Atomic increment with condition
    const result = await ddb.send(new UpdateItemCommand({
      TableName: 'UserQuotas',
      Key: { 
        pk: { S: `USER#${userId}` },
        sk: { S: `QUOTA#${today}` }
      },
      UpdateExpression: 'ADD dailyTokens :tokens SET #month = if_not_exists(#month, :zero) + :tokens',
      ConditionExpression: 'attribute_not_exists(dailyTokens) OR dailyTokens < :dailyLimit',
      ExpressionAttributeNames: {
        '#month': `monthlyTokens_${month}`
      },
      ExpressionAttributeValues: {
        ':tokens': { N: String(tokensToConsume) },
        ':zero': { N: '0' },
        ':dailyLimit': { N: String(quota.dailyTokenLimit) }
      },
      ReturnValues: 'ALL_NEW'
    }));

    const newDaily = parseInt(result.Attributes?.dailyTokens?.N || '0');

    return {
      allowed: true,
      remaining: quota.dailyTokenLimit - newDaily
    };

  } catch (error) {
    if ((error as Error).name === 'ConditionalCheckFailedException') {
      return { allowed: false, remaining: 0 };
    }
    throw error;
  }
}

import { 
  BedrockRuntimeClient, 
  InvokeModelWithResponseStreamCommand 
} from '@aws-sdk/client-bedrock-runtime';

async function* streamResponse(
  prompt: string,
  modelId: string = 'anthropic.claude-3-sonnet-20240229-v1:0'
): AsyncGenerator<string, void, unknown> {
  const client = new BedrockRuntimeClient({});

  const command = new InvokeModelWithResponseStreamCommand({
    modelId,
    body: JSON.stringify({
      anthropic_version: 'bedrock-2023-05-31',
      max_tokens: 4096,
      messages: [{ role: 'user', content: prompt }]
    }),
    contentType: 'application/json'
  });

  const response = await client.send(command);

  if (response.body) {
    for await (const event of response.body) {
      if (event.chunk?.bytes) {
        const chunk = JSON.parse(new TextDecoder().decode(event.chunk.bytes));

        if (chunk.type === 'content_block_delta') {
          yield chunk.delta.text;
        }

        // Handle stop conditions
        if (chunk.type === 'message_stop') {
          return;
        }
      }
    }
  }
}

// Usage in an API route
export async function GET(request: Request) {
  const { prompt } = await request.json();

  const encoder = new TextEncoder();
  const stream = new ReadableStream({
    async start(controller) {
      try {
        for await (const chunk of streamResponse(prompt)) {
          // Format as Server-Sent Events
          controller.enqueue(
            encoder.encode(`data: ${JSON.stringify({ text: chunk })}\n\n`)
          );
        }
        controller.enqueue(encoder.encode('data: [DONE]\n\n'));
        controller.close();
      } catch (error) {
        controller.enqueue(
          encoder.encode(`data: ${JSON.stringify({ error: 'Stream failed' })}\n\n`)
        );
        controller.close();
      }
    }
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive'
    }
  });
}

import { CloudWatchClient, PutMetricDataCommand } from '@aws-sdk/client-cloudwatch';

interface GenAIMetrics {
  requestId: string;
  modelId: string;
  userId?: string;
  inputTokens: number;
  outputTokens: number;
  latencyMs: number;
  cached: boolean;
  guardrailTriggered: boolean;
  errorType?: string;
}

async function recordMetrics(metrics: GenAIMetrics): Promise<void> {
  const cloudwatch = new CloudWatchClient({});
  const timestamp = new Date();

  const dimensions = [
    { Name: 'ModelId', Value: metrics.modelId },
    { Name: 'Application', Value: process.env.APP_NAME || 'genai-app' }
  ];

  const metricData = [
    // Latency
    {
      MetricName: 'RequestLatency',
      Dimensions: dimensions,
      Value: metrics.latencyMs,
      Unit: 'Milliseconds',
      Timestamp: timestamp
    },
    // Token usage
    {
      MetricName: 'InputTokens',
      Dimensions: dimensions,
      Value: metrics.inputTokens,
      Unit: 'Count',
      Timestamp: timestamp
    },
    {
      MetricName: 'OutputTokens',
      Dimensions: dimensions,
      Value: metrics.outputTokens,
      Unit: 'Count',
      Timestamp: timestamp
    },
    // Cost estimation (approximate)
    {
      MetricName: 'EstimatedCost',
      Dimensions: dimensions,
      Value: estimateCost(metrics.modelId, metrics.inputTokens, metrics.outputTokens),
      Unit: 'None', // USD in cents
      Timestamp: timestamp
    },
    // Cache effectiveness
    {
      MetricName: 'CacheHit',
      Dimensions: dimensions,
      Value: metrics.cached ? 1 : 0,
      Unit: 'Count',
      Timestamp: timestamp
    },
    // Safety
    {
      MetricName: 'GuardrailTriggered',
      Dimensions: dimensions,
      Value: metrics.guardrailTriggered ? 1 : 0,
      Unit: 'Count',
      Timestamp: timestamp
    }
  ];

  // Add error metric if applicable
  if (metrics.errorType) {
    metricData.push({
      MetricName: 'Errors',
      Dimensions: [...dimensions, { Name: 'ErrorType', Value: metrics.errorType }],
      Value: 1,
      Unit: 'Count',
      Timestamp: timestamp
    });
  }

  await cloudwatch.send(new PutMetricDataCommand({
    Namespace: 'GenAI/Production',
    MetricData: metricData
  }));
}

// Model pricing (simplified - check current Bedrock pricing)
function estimateCost(modelId: string, inputTokens: number, outputTokens: number): number {
  const pricing: Record<string, { input: number; output: number }> = {
    'anthropic.claude-3-sonnet-20240229-v1:0': { input: 0.003, output: 0.015 },
    'anthropic.claude-3-haiku-20240307-v1:0': { input: 0.00025, output: 0.00125 },
    'amazon.titan-text-express-v1': { input: 0.0002, output: 0.0006 }
  };

  const modelPricing = pricing[modelId] || { input: 0.001, output: 0.002 };
  // Return cost in cents (multiply by 100)
  return ((inputTokens / 1000) * modelPricing.input + (outputTokens / 1000) * modelPricing.output) * 100;
}

