async function processRAGRequest(query: string): Promise<string> {
  const segment = AWSXRay.getSegment();

  // Trace embedding generation
  const embeddingSubsegment = segment?.addNewSubsegment('GenerateEmbedding');
  embeddingSubsegment?.addAnnotation('query_length', query.length);

  try {
    const embedding = await generateEmbedding(query);
    embeddingSubsegment?.addMetadata('embedding_dimension', embedding.length);
    embeddingSubsegment?.close();
  } catch (error) {
    embeddingSubsegment?.addError(error as Error);
    embeddingSubsegment?.close();
    throw error;
  }

  // Trace vector search
  const searchSubsegment = segment?.addNewSubsegment('VectorSearch');
  searchSubsegment?.addAnnotation('index', 'knowledge-base');

  try {
    const results = await searchVectorStore(embedding);
    searchSubsegment?.addMetadata('results_count', results.length);
    searchSubsegment?.addMetadata('top_score', results[0]?.score);
    searchSubsegment?.close();
  } catch (error) {
    searchSubsegment?.addError(error as Error);
    searchSubsegment?.close();
    throw error;
  }

  // Trace LLM invocation
  const llmSubsegment = segment?.addNewSubsegment('LLMInvocation');
  llmSubsegment?.addAnnotation('model', 'claude-3-sonnet');

  try {
    const response = await invokeModel(query, context);
    llmSubsegment?.addMetadata('output_tokens', response.usage.output_tokens);
    llmSubsegment?.close();
    return response.content;
  } catch (error) {
    llmSubsegment?.addError(error as Error);
    llmSubsegment?.close();
    throw error;
  }
}

interface DegradationState {
  level: 'normal' | 'degraded' | 'minimal' | 'offline';
  availableFeatures: string[];
  unavailableFeatures: string[];
}

async function handleQueryWithDegradation(
  query: string
): Promise<{ response: string; degradationState: DegradationState }> {
  // Try full-featured response
  try {
    const response = await fullRAGResponse(query);
    return {
      response,
      degradationState: {
        level: 'normal',
        availableFeatures: ['rag', 'streaming', 'citations'],
        unavailableFeatures: []
      }
    };
  } catch (ragError) {
    console.warn('RAG failed, attempting degraded mode:', ragError);
  }

  // Try direct model response (no RAG)
  try {
    const response = await directModelResponse(query);
    return {
      response: response + '\n\n*Note: This response was generated without access to the knowledge base.*',
      degradationState: {
        level: 'degraded',
        availableFeatures: ['model_response'],
        unavailableFeatures: ['rag', 'citations']
      }
    };
  } catch (modelError) {
    console.warn('Direct model failed, trying cache:', modelError);
  }

  // Try cached response for similar queries
  try {
    const cachedResponse = await findSimilarCachedResponse(query);
    if (cachedResponse) {
      return {
        response: cachedResponse + '\n\n*Note: This is a cached response and may not reflect the latest information.*',
        degradationState: {
          level: 'minimal',
          availableFeatures: ['cached_response'],
          unavailableFeatures: ['rag', 'model_response', 'citations']
        }
      };
    }
  } catch (cacheError) {
    console.warn('Cache lookup failed:', cacheError);
  }

  // Complete fallback - static response
  return {
    response: generateStaticFallback(query),
    degradationState: {
      level: 'offline',
      availableFeatures: ['static_fallback'],
      unavailableFeatures: ['rag', 'model_response', 'cached_response', 'citations']
    }
  };
}

function generateStaticFallback(query: string): string {
  // Categorize query and return appropriate static response
  const category = categorizeQuery(query);

  const staticResponses: Record<string, string> = {
    pricing: 'For current pricing information, please visit aws.amazon.com/bedrock/pricing',
    documentation: 'AWS documentation is available at docs.aws.amazon.com',
    default: 'We\'re experiencing technical difficulties. Please try again in a few minutes. If the issue persists, contact support.'
  };

  return staticResponses[category] || staticResponses.default;
}

import { ComprehendClient, DetectPiiEntitiesCommand } from '@aws-sdk/client-comprehend';
import { 
  BedrockRuntimeClient, 
  ApplyGuardrailCommand 
} from '@aws-sdk/client-bedrock-runtime';

interface ValidationResult {
  valid: boolean;
  sanitizedInput?: string;
  rejectionReason?: string;
  piiDetected?: string[];
}

async function validateInput(userInput: string): Promise<ValidationResult> {
  // Length check
  if (userInput.length > 10000) {
    return { valid: false, rejectionReason: 'Input exceeds maximum length' };
  }

  if (userInput.length < 2) {
    return { valid: false, rejectionReason: 'Input too short' };
  }

  // Basic injection pattern detection
  const injectionPatterns = [
    /ignore\s+(all\s+)?previous\s+instructions/i,
    /system\s*:\s*you\s+are/i,
    /\[\s*INST\s*\]/i,
    /<\|im_start\|>/i
  ];

  for (const pattern of injectionPatterns) {
    if (pattern.test(userInput)) {
      return { valid: false, rejectionReason: 'Potentially malicious input detected' };
    }
  }

  // PII detection with Comprehend
  const comprehend = new ComprehendClient({});
  const piiResult = await comprehend.send(new DetectPiiEntitiesCommand({
    Text: userInput,
    LanguageCode: 'en'
  }));

  const piiTypes = piiResult.Entities?.map(e => e.Type!) || [];
  let sanitizedInput = userInput;

  // Redact sensitive PII (keep names/dates for context)
  const sensitiveTypes = ['SSN', 'CREDIT_DEBIT_NUMBER', 'BANK_ACCOUNT_NUMBER', 'PIN'];
  const sensitivePII = piiTypes.filter(t => sensitiveTypes.includes(t));

  if (sensitivePII.length > 0) {
    for (const entity of piiResult.Entities || []) {
      if (sensitiveTypes.includes(entity.Type!)) {
        const start = entity.BeginOffset!;
        const end = entity.EndOffset!;
        sanitizedInput = 
          sanitizedInput.slice(0, start) + 
          '[REDACTED]' + 
          sanitizedInput.slice(end);
      }
    }
  }

  // Guardrail check
  const bedrock = new BedrockRuntimeClient({});
  const guardrailResult = await bedrock.send(new ApplyGuardrailCommand({
    guardrailIdentifier: process.env.GUARDRAIL_ID,
    guardrailVersion: 'DRAFT',
    source: 'INPUT',
    content: [{ text: { text: sanitizedInput } }]
  }));

  if (guardrailResult.action === 'GUARDRAIL_INTERVENED') {
    return { 
      valid: false, 
      rejectionReason: 'Content policy violation',
      piiDetected: piiTypes
    };
  }

  return {
    valid: true,
    sanitizedInput,
    piiDetected: piiTypes.length > 0 ? piiTypes : undefined
  };
}
